const competitors = [
  { username: 'englishforukrainians', name: 'English for Ukrainians' },
  { username: 'greenforestschool', name: 'Green Forest School' },
  { username: 'cambridge_ua', name: 'Cambridge UA' },
  { username: 'english_with_ann', name: 'English with Ann' },
  { username: 'learn_english_ua', name: 'Learn English UA' },
  { username: 'speak_english_ua', name: 'Speak English UA' },
  { username: 'englishwithmax', name: 'English with Max' },
  { username: 'duolingo_ua', name: 'Duolingo UA' }
];
return competitors.map(c => ({ json: c }));

const html = $input.first().json;
const channelName = $('📋 Список конкурентів').item.json.name;
const username = $('📋 Список конкурентів').item.json.username;

// Парсимо підписників
const subsMatch = html.data?.match(/([\d\s,]+)\s*(?:subscribers|підписників)/i);
const subscribers = subsMatch ? subsMatch[1].replace(/[\s,]/g,'') : 'N/A';

// Парсимо ріст
const growthMatch = html.data?.match(/([+-]?[\d,]+)\s*(?:за місяць|monthly|per month)/i);
const growth = growthMatch ? growthMatch[1] : 'N/A';

// Парсимо ER
const erMatch = html.data?.match(/([\d.]+)%?\s*(?:ER|engagement)/i);
const er = erMatch ? erMatch[1] : 'N/A';

return [{ json: {
  username,
  name: channelName,
  subscribers,
  monthly_growth: growth,
  engagement_rate: er,
  url: `https://t.me/${username}`,
  checked_at: new Date().toISOString()
}}];

const html = $input.first().json.data || '';
const stats = $('📊 Парсинг статистики').item.json;

// Витягуємо тексти постів
const postMatches = html.match(/<div class="tgme_widget_message_text[^>]*>([\s\S]*?)<\/div>/g) || [];
const posts = postMatches.slice(0, 10).map(p => 
  p.replace(/<[^>]+>/g, ' ').replace(/\s+/g,' ').trim().slice(0, 200)
).filter(p => p.length > 20);

// Визначаємо типи контенту
const hasQuiz = posts.some(p => /quiz|тест|питан|question/i.test(p));
const hasVocab = posts.some(p => /word|слово|vocabulary|vocab/i.test(p));
const hasGrammar = posts.some(p => /grammar|граматик/i.test(p));
const hasMeme = posts.some(p => /meme|мем|funny|joke/i.test(p));
const hasAudio = html.includes('voice') || html.includes('audio');

return [{ json: {
  ...stats,
  content_types: {
    quiz: hasQuiz,
    vocabulary: hasVocab,
    grammar: hasGrammar,
    meme: hasMeme,
    audio: hasAudio
  },
  recent_posts_preview: posts.slice(0, 3),
  posts_count: posts.length
}}];

const aiAnalysis = $('🤖 AI — Аналіз і рекомендації').item.json.message?.content || '';
const allData = $('📦 Збір всіх даних').item.json;
const date = new Date().toLocaleDateString('uk-UA');

// Топ по підписниках
const channels = Array.isArray(allData) ? allData : [allData];
const sorted = channels
  .filter(c => c.subscribers && c.subscribers !== 'N/A')
  .sort((a,b) => parseInt(b.subscribers||0) - parseInt(a.subscribers||0));

let statsTable = '📊 *Дані конкурентів:*\n';
sorted.forEach(c => {
  const types = c.content_types || {};
  const typeList = Object.entries(types).filter(([,v])=>v).map(([k])=>k).join(', ') || 'невідомо';
  statsTable += `\n• @${c.username}: ${c.subscribers} підп. | ER: ${c.engagement_rate}% | Контент: ${typeList}`;
});

const report = `🔍 *ЩОТИЖНЕВИЙ ЗВІТ КОНКУРЕНТІВ*\n📅 ${date}\n\n${statsTable}\n\n---\n\n${aiAnalysis}`;

return [{ json: { report } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.competitors) staticData.competitors = {};
if (!staticData.competitorHistory) staticData.competitorHistory = [];

const allData = $('📦 Збір всіх даних').item.json;
const channels = Array.isArray(allData) ? allData : [allData];

// Зберігаємо поточний стан
channels.forEach(c => {
  if (c.username) staticData.competitors[c.username] = {
    ...c,
    updated_at: new Date().toISOString()
  };
});

// Зберігаємо в історію
staticData.competitorHistory.push({
  date: new Date().toISOString().split('T')[0],
  data: channels
});

// Залишаємо тільки 12 тижнів
if (staticData.competitorHistory.length > 12) {
  staticData.competitorHistory = staticData.competitorHistory.slice(-12);
}

return [{ json: { saved: true, count: channels.length } }];
